<template><div><el-card shadow="never"><div class="title-row"><b>组织人员管理</b><span>最近同步状态：<el-tag :type="latest?.status==='SUCCESS'?'success':'danger'">{{latest?.status||'未同步'}}</el-tag> {{latest?.endedAt||latest?.startedAt||''}}</span></div><div class="toolbar"><el-input v-model="query.keyword" placeholder="姓名/企微账号" clearable/><el-select v-model="query.status" placeholder="成员状态" clearable><el-option label="在职" :value="1"/><el-option label="离职" :value="0"/></el-select><el-select v-model="query.gender" placeholder="性别" clearable><el-option label="男" value="MALE"/><el-option label="女" value="FEMALE"/><el-option label="未知" value="UNKNOWN"/></el-select><el-select v-model="query.syncStatus" placeholder="同步状态" clearable><el-option label="成功" value="SUCCESS"/><el-option label="失败" value="FAILED"/></el-select><el-button type="primary" @click="loadPeople">查询</el-button><el-button @click="reset">重置</el-button><el-button type="success" :loading="syncing" @click="sync">同步企业微信</el-button><el-button type="warning" plain @click="logsVisible=true">查看同步日志</el-button></div></el-card>
<el-row :gutter="16" style="margin-top:16px"><el-col :span="6"><el-card class="full"><template #header><div class="title-row"><span>组织架构</span><el-button link @click="selectDepartment(null)">全部部门</el-button></div></template><div class="current">当前：{{currentName}}（{{total}}人）</div><el-tree :data="tree" node-key="id" :props="{label:'label',children:'children'}" default-expand-all highlight-current @node-click="(n:any)=>selectDepartment(n)"/></el-card></el-col><el-col :span="18"><el-card class="full"><el-tabs v-model="tab"><el-tab-pane label="成员列表" name="members"><el-table :data="people" v-loading="loading" stripe><el-table-column label="姓名" min-width="140"><template #default="{row}"><div class="member"><el-avatar :size="32" :src="row.avatarUrl">{{row.name?.slice(0,1)}}</el-avatar><div>{{row.name}}<small>{{row.wecomUserId}}</small></div></div></template></el-table-column><el-table-column prop="positionName" label="职位"/><el-table-column prop="mobileMasked" label="手机号"/><el-table-column label="性别" width="70"><template #default="{row}">{{genderLabel(row.gender)}}</template></el-table-column><el-table-column label="部门"><template #default="{row}">{{row.primaryDepartment?.name||'-'}}</template></el-table-column><el-table-column label="成员状态" width="90"><template #default="{row}"><el-tag :type="row.status===1?'success':'danger'">{{row.status===1?'在职':'离职'}}</el-tag></template></el-table-column><el-table-column label="同步状态" width="90"><template #default="{row}"><el-tag :type="row.syncStatus==='SUCCESS'?'success':'danger'">{{row.syncStatus==='SUCCESS'?'成功':'失败'}}</el-tag></template></el-table-column><el-table-column prop="syncedAt" label="同步时间" width="170"/><el-table-column label="操作" width="90"><template #default="{row}"><el-button link @click="showPerson(row)">查看详情</el-button></template></el-table-column></el-table><el-pagination class="pager" background layout="prev,pager,next,total" :total="total" :page-size="query.size" @current-change="(p:number)=>{query.page=p;loadPeople()}"/></el-tab-pane><el-tab-pane label="部门详情" name="department"><el-descriptions v-if="departmentDetail" border :column="1"><el-descriptions-item label="部门名称">{{departmentDetail.department.name}}</el-descriptions-item><el-descriptions-item label="成员数量">{{departmentDetail.memberCount}}</el-descriptions-item><el-descriptions-item label="状态">{{departmentDetail.department.status===1?'启用':'停用'}}</el-descriptions-item><el-descriptions-item label="同步时间">{{departmentDetail.department.syncedAt}}</el-descriptions-item></el-descriptions><el-empty v-else description="请选择部门"/></el-tab-pane></el-tabs></el-card></el-col></el-row>
<el-drawer v-model="detailVisible" title="成员详情" size="520px"><el-descriptions v-if="personDetail" border :column="1"><el-descriptions-item label="姓名">{{personDetail.name}}</el-descriptions-item><el-descriptions-item label="企微账号">{{personDetail.wecomUserId}}</el-descriptions-item><el-descriptions-item label="职位">{{personDetail.positionName||'-'}}</el-descriptions-item><el-descriptions-item label="手机号">{{personDetail.mobileMasked||'-'}}</el-descriptions-item><el-descriptions-item label="邮箱">{{personDetail.email||'-'}}</el-descriptions-item><el-descriptions-item label="所属部门"><el-tag v-for="d in personDetail.departments" :key="d.id">{{d.name}}</el-tag></el-descriptions-item><el-descriptions-item label="同步状态">{{personDetail.syncStatus}}</el-descriptions-item><el-descriptions-item v-if="personDetail.syncError" label="失败原因">{{personDetail.syncError}}</el-descriptions-item></el-descriptions></el-drawer>
<el-dialog v-model="logsVisible" title="组织同步日志" width="800px"><el-table :data="logs"><el-table-column prop="startedAt" label="开始时间"/><el-table-column prop="status" label="状态"/><el-table-column prop="departmentCount" label="部门"/><el-table-column prop="personCount" label="成员"/><el-table-column prop="errorDetail" label="错误"/></el-table></el-dialog></div></template>
<script setup lang="ts">import{computed,onMounted,reactive,ref}from'vue';import{ElMessage}from'element-plus';import{getOrganizationDepartment,getOrganizationDepartments,getOrganizationPerson,getOrganizationPersons,listSyncLogs,syncWecom}from'@/api';const tree=ref<any[]>([]),people=ref<any[]>([]),logs=ref<any[]>([]),total=ref(0),loading=ref(false),syncing=ref(false),tab=ref('members'),departmentDetail=ref<any>(null),personDetail=ref<any>(null),detailVisible=ref(false),logsVisible=ref(false);const query=reactive<any>({departmentId:null,keyword:'',status:undefined,gender:'',syncStatus:'',page:1,size:20});const latest=computed(()=>logs.value[0]);const currentName=computed(()=>departmentDetail.value?.department?.name||'全部部门');function build(items:any[]){const map=new Map(items.map(x=>[x.id,{...x,label:`${x.name}（${x.memberCount}）`,children:[]}])) as Map<number,any>;const roots:any[]=[];map.forEach(x=>{const parent=[...map.values()].find(y=>y.wecomDepartmentId===x.parentWecomDepartmentId);parent?parent.children.push(x):roots.push(x)});return roots}async function loadBase(){const[d,l]=await Promise.all([getOrganizationDepartments(),listSyncLogs()]);tree.value=build(d.data.data);logs.value=l.data.data}async function loadPeople(){loading.value=true;try{const r=await getOrganizationPersons(query);people.value=r.data.data.records;total.value=r.data.data.total}finally{loading.value=false}}async function selectDepartment(node:any){query.departmentId=node?.id||null;query.page=1;departmentDetail.value=node?(await getOrganizationDepartment(node.id)).data.data:null;loadPeople()}async function showPerson(row:any){personDetail.value=(await getOrganizationPerson(row.id)).data.data;detailVisible.value=true}function reset(){Object.assign(query,{departmentId:null,keyword:'',status:undefined,gender:'',syncStatus:'',page:1,size:20});departmentDetail.value=null;loadPeople()}async function sync(){syncing.value=true;try{await syncWecom();ElMessage.success('组织同步完成');await Promise.all([loadBase(),loadPeople()])}finally{syncing.value=false}}function genderLabel(v:string){return v==='MALE'?'男':v==='FEMALE'?'女':'未知'}onMounted(async()=>{await loadBase();await loadPeople()})</script><style scoped>.title-row{display:flex;justify-content:space-between;align-items:center}.toolbar{display:flex;gap:10px;margin-top:18px}.toolbar .el-input{width:190px}.toolbar .el-select{width:140px}.full{min-height:650px}.current{color:#606266;margin-bottom:12px}.member{display:flex;gap:9px;align-items:center}.member small{display:block;color:#909399}.pager{margin-top:14px;justify-content:flex-end}</style>
